import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote — base premiums per item", () => {
    it.todo("should charge 5 G for an empty item list (processing fee only)");
    it.todo("should quote a single sword at 105 G (100 base + 5 fee)");
    it.todo("should quote a single amulet at 65 G (60 base + 5 fee)");
    it.todo("should quote a single staff at 85 G (80 base + 5 fee)");
    it.todo("should quote a single potion at 45 G (40 base + 5 fee)");
    it.todo("should quote a single rune component at 30 G (25 base + 5 fee)");
    it.todo(
      "should quote a single moonstone component at 30 G (25 base + 5 fee)",
    );
  });

  describe("quote — component building block of 3 alike", () => {
    it.todo("should charge 50 G base for 2 runes (no block)");
    it.todo("should charge 60 G base for 3 runes (block applies)");
    it.todo("should charge 100 G base for 4 runes (no block, needs exactly 3)");
    it.todo("should charge 175 G base for 7 runes (one block of 3 + 4 single)");
  });

  describe("quote — 'alike' means same component type", () => {
    it.todo(
      "should charge 75 G base for 2 runes + 1 moonstone (no block: different types)",
    );
    it.todo(
      "should charge 120 G base for 3 runes + 3 moonstones (two separate blocks)",
    );
  });

  describe("quote — item-specific modifiers", () => {
    it.todo("should add 50% curse surcharge to a cursed sword (100 -> 150)");
    it.todo(
      "should add 30% surcharge to a highly enchanted sword at enchantment exactly 5",
    );
    it.todo(
      "should NOT add high-enchantment surcharge to a sword at enchantment 4",
    );
    it.todo(
      "should stack curse and high-enchantment surcharges on the same item",
    );
  });

  describe("quote — modifier scope on multi-item policies", () => {
    it.todo(
      "should apply the curse surcharge only to the cursed item's base premium, not the policy total (cursed sword + plain amulet -> 210 before fee)",
    );
  });

  describe("quote — policy-wide modifiers", () => {
    it.todo(
      "should apply 20% loyalty discount for a customer with exactly 2 years",
    );
    it.todo("should NOT apply loyalty discount below 2 years");
    it.todo(
      "should apply 10% first-insurance surcharge to the policy base premium",
    );
    it.todo(
      "should apply 15% follow-up discount on the customer's second quote in the scenario",
    );
    it.todo("should NOT apply follow-up discount on the first quote");
  });

  describe("quote — rounding up in MHPCO's favor", () => {
    it.todo("should round a premium of 197.5 G up to 198 G");
    it.todo(
      "should keep intermediate amounts as fractions and round only the final premium",
    );
  });

  describe("quote — integration examples", () => {
    it.todo(
      "should quote a newcomer's cursed sword (0 years, first contract) at 165 G",
    );
    it.todo(
      "should quote a long-standing customer's second contract cursed enchanted sword at 160 G",
    );
  });

  describe("claim — standard reimbursement (no special clause)", () => {
    it.todo(
      "should pay 400 G for a regular sword with 500 G damage (full minus 100 deductible)",
    );
    it.todo(
      "should pay 100 G for a rune with 200 G damage (no enchantment/material clause)",
    );
  });

  describe("claim — high-enchantment clause (>= 8)", () => {
    it.todo(
      "should reimburse a steel sword at enchantment 9 at 50% then deductible (1000 damage -> 400)",
    );
  });

  describe("claim — dragon-material clause", () => {
    it.todo(
      "should fully reimburse a dragon sword at enchantment 5 then deductible (800 damage -> 700)",
    );
  });

  describe("claim — high-enchantment wins over dragon material", () => {
    it.todo(
      "should apply the 50% rule when a dragon sword has enchantment 9 (1000 damage -> 400)",
    );
    it.todo(
      "should apply the 50% rule when a dragon sword has enchantment exactly 8 (1000 damage -> 400)",
    );
  });

  describe("claim — deductible per damage event", () => {
    it.todo(
      "should apply the 100 G deductible once per damaged item (sword 500 + amulet 300 -> 600)",
    );
  });

  describe("claim — cap based on unmodified insurance sum", () => {
    it.todo(
      "should cap total payout at 2x the unmodified insurance sum across successive claims (1000 sum, cap 2000; two 1500 claims -> 1400 then 600)",
    );
    it.todo(
      "should base the cap on unmodified insurance value, ignoring premium modifiers (cursed sword cap 2000)",
    );
  });

  describe("claim — payout rounding down in MHPCO's favor", () => {
    it.todo("should round a payout of 350.5 G down to 350 G");
  });

  describe("claim — multiple items of the same type", () => {
    it.todo(
      "should treat two sword damage entries as separate events each with its own deductible (insurance sum 2000, cap 4000)",
    );
  });

  describe("scenario — sequential steps", () => {
    it.todo(
      "should process a quote followed by a claim against that policy via its step index",
    );
  });

  describe("errors", () => {
    it.todo("should reject a quote with an unknown item type");
    it.todo("should reject a claim whose damaged item is not part of the policy");
    it.todo(
      "should reject a claim with more damage entries of a type than the policy covers",
    );
    it.todo("should reject a claim with a negative damage amount");
  });
});

import { describe, it, expect } from "vitest";

// CLI integration tests: spawn src/cli.ts, write a JSON scenario to stdin,
// read the JSON results from stdout, and assert on the process exit code.

describe("claim-office CLI (stdin -> stdout)", () => {
  it.todo("should read a scenario from stdin and write a results JSON to stdout");
  it.todo(
    "should return one result per step, in the same order as the input steps",
  );
  it.todo(
    "should emit a quote result with a premium field for a quote step",
  );
  it.todo(
    "should emit a claim result with payout and remainingCap fields for a claim step",
  );
  it.todo(
    "should process the schema example (amulet quote then fire claim) end to end",
  );

  describe("error exits (non-zero status, stderr, no results on stdout)", () => {
    it.todo("should exit non-zero for a quote with an unknown item type");
    it.todo(
      "should exit non-zero for a claim referencing an item not in the policy",
    );
    it.todo(
      "should exit non-zero for a claim with more damage entries than the policy covers",
    );
    it.todo("should exit non-zero for a claim with a negative damage amount");
  });
});
